package Session;

use strict;
use warnings;
use Storable qw(nstore retrieve);
use Digest::SHA qw(sha1_hex);
use File::Spec;

sub new {
    my ($class, %args) = @_;
    my $cgi = $args{cgi} or die "cgi parameter required";
    my $cookie_name = $args{cookie_name} || 'SESSIONID';

    my $sid = $cgi->cookie($cookie_name);
    $sid = undef unless defined $sid && $sid =~ /^[A-Za-z0-9]{40}$/;
    $sid ||= _generate_sid();

    my $self = bless {
        cgi         => $cgi,
        cookie_name => $cookie_name,
        sid         => $sid,
        data        => {},
    }, $class;

    $self->_load;
    return $self;
}

sub _generate_sid { sha1_hex( rand() . $$ . time() . {} ) }

sub _file {
    my ($self) = @_;
    File::Spec->catfile( '/tmp', 'sess_' . $self->{sid} );
}

sub _load {
    my ($self) = @_;
    my $file = $self->_file;
    if ( -e $file ) {
        eval { $self->{data} = retrieve($file) || {} };
        $self->{data} ||= {};
    }
}

sub param {
    my ( $self, $key, $value ) = @_;
    $self->{data}{$key} = $value if @_ == 3;
    return $self->{data}{$key};
}

sub save  { my ($self) = @_; nstore( $self->{data}, $self->_file ); }
sub clear { my ($self) = @_; unlink $self->_file if -e $self->_file }

sub cookie {
    my ( $self, %extra ) = @_;
    return $self->{cgi}->cookie(
        -name  => $self->{cookie_name},
        -value => $self->{sid},
        -path  => '/',
        %extra,
    );
}

