#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use FindBin;
use lib $FindBin::Bin;
use Session;

my $cgi      = CGI->new;
my $session  = Session->new( cgi => $cgi );

my $counter = $session->param('counter') || 0;
$counter++;
$session->param( counter => $counter );
$session->save;

print $cgi->header(
    -type   => 'text/plain',
    -cookie => $session->cookie
);
print "Session ID : $session->{sid}\n";
print "Visit count: $counter\n";